content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一杯紅茶嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī bēi hóng chá ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 bei1 hong2 cha2 ma0?",
      "translation_en": "Excuse me, could you give me a cup of black tea?",
      "translation_ko": "실례합니다, 홍차 한 잔 주시겠어요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "店員，可以給我一個袋子嗎？",
      "pinyin": "Diàn yuán, kě yǐ gěi wǒ yī gè dài zi ma?",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi5 ma0?",
      "translation_en": "Shop assistant, could you give me a bag?",
      "translation_ko": "점원님, 봉투 하나 주시겠어요?"
    },
    {
      "text": "我想要一杯豆漿，可以幫我外帶嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, kě yǐ bāng wǒ wài dài ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, ke3 yi3 bang1 wo3 wai4 dai4 ma0?",
      "translation_en": "I would like a cup of soy milk, could you make it for takeout?",
      "translation_ko": "두유 한 잔을 원하는데 포장해 주시겠어요?"
    },
    {
      "text": "麻煩你，可以給我半糖的綠茶嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ bàn táng de lǜ chá ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 ban4 tang2 de5 lü4 cha2 ma0?",
      "translation_en": "Excuse me, could you give me a half-sugar green tea?",
      "translation_ko": "실례합니다, 반당 녹차를 주시겠어요?"
    },
    {
      "text": "不好意思，可以幫我少冰嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ shǎo bīng ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 shao3 bing1 ma0?",
      "translation_en": "Excuse me, could you make it less ice for me?",
      "translation_ko": "죄송합니다, 얼음 적게 해 주시겠어요?"
    },
    {
      "text": "客人，可以給我菜單看一下嗎？",
      "pinyin": "Kè rén, kě yǐ gěi wǒ cài dān kàn yī xià ma?",
      "pinyin_numeric": "ke4 ren2, ke3 yi3 gei3 wo3 cai4 dan1 kan4 yi1 xia4 ma0?",
      "translation_en": "Customer, could you give me the menu to look at?",
      "translation_ko": "손님, 메뉴판을 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯大杯的拿鐵，可以內用嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de ná tiě, kě yǐ nèi yòng ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 na2 tie3, ke3 yi3 nei4 yong4 ma0?",
      "translation_en": "I would like a large latte, can I have it for here?",
      "translation_ko": "큰 라떼 한 잔을 원하는데 매장에서 먹을 수 있을까요?"
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Excuse me, could you give me a straw?",
      "translation_ko": "실례합니다, 빨대 하나 주시겠어요?"
    }
  ]
}
